const minEl = document.getElementById("min");
const prefEl = document.getElementById("pref");
const maxEl = document.getElementById("max");
const vwEl = document.getElementById("vw");

const text = document.getElementById("text");
const curve = document.getElementById("curve");

const cssCode = document.getElementById("cssCode");
const jsCode = document.getElementById("jsCode");
const values = document.getElementById("values");

function clamp(v, min, max) {
  return Math.min(Math.max(v, min), max);
}

function update() {
  const min = parseFloat(minEl.value);
  const pref = parseFloat(prefEl.value);
  const max = parseFloat(maxEl.value);
  const vw = parseFloat(vwEl.value);

  const prefPx = vw * (pref / 100);
  const size = clamp(prefPx, min, max);

  text.style.fontSize = size + "px";

  cssCode.innerHTML = `CSS<br><code>font-size: clamp(${min}px, ${pref}vw, ${max}px)</code>`;

  jsCode.innerHTML = `JS<br><code>Math.min(Math.max(v, ${min}), ${max})</code>`;

  values.innerHTML = `viewport = ${vw}px<br>
preferred = ${prefPx.toFixed(2)}px<br>
result = <b>${size.toFixed(2)}px</b>`;

  const points = [];

  for (let x = 0; x <= 100; x++) {
    const vwSim = 320 + (x / 100) * (1600 - 320);
    const val = clamp(vwSim * (pref / 100), min, max);

    const y = 100 - (val / max) * 100;

    points.push(`${x},${y}`);
  }

  curve.setAttribute("d", "M" + points.join(" L"));
}

[minEl, prefEl, maxEl, vwEl].forEach((e) =>
  e.addEventListener("input", update)
);

update();

style.css:
:root {
  --bg: #060b17;
  --panel: #0f172a;
  --accent: #22d3ee;
  --accent2: #8b5cf6;
  --text: #e2e8f0;
}

* {
  box-sizing: border-box;
  font-family: system-ui;
}

body {
  margin: 0;
  background: radial-gradient(circle at 20% 20%, #1e1b4b 0%, transparent 40%),
    radial-gradient(circle at 80% 70%, #3d55dc 0%, transparent 40%), var(--bg);
  color: var(--text);
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px;
}

.app {
  width: min(1100px, 92vw);
  background: rgba(15, 23, 42, 0.85);
  backdrop-filter: blur(15px);
  border-radius: 20px;
  padding: 35px;
  box-shadow: 0 25px 80px rgba(0, 0, 0, 0.7);
}

h1 {
  text-align: center;
  margin-top: 0;
  background: linear-gradient(90deg, var(--accent), var(--accent2));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.controls {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 20px;
  margin-bottom: 30px;
}

.control {
  background: #020617;
  padding: 16px;
  border-radius: 12px;
}

label {
  font-size: 0.8rem;
  opacity: 0.8;
  display: block;
  margin-bottom: 6px;
}

input[type="range"] {
  width: 100%;
}

.preview {
  background: #020617;
  border-radius: 14px;
  padding: 60px 20px;
  text-align: center;
  margin-bottom: 30px;
}

.previewText {
  font-weight: 800;
  transition: 0.2s;
}

.graph {
  background: #020617;
  border-radius: 14px;
  padding: 20px;
  margin-bottom: 25px;
}

svg {
  width: 100%;
  height: 160px;
}

.zoneMin {
  fill: #22c55e22;
}
.zoneMax {
  fill: #ef444422;
}

.curve {
  fill: none;
  stroke: var(--accent);
  stroke-width: 3;
}

.line {
  stroke-dasharray: 4 4;
}

.minLine {
  stroke: #22c55e;
}
.maxLine {
  stroke: #ef4444;
}
.prefLine {
  stroke: #eab308;
}

.compare {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 15px;
}

.card {
  background: #020617;
  padding: 15px;
  border-radius: 10px;
  font-size: 0.9rem;
}

code {
  color: var(--accent);
}
